import React, { useEffect, useState } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { motion, AnimatePresence } from 'framer-motion';
import { Link } from 'react-router-dom';
import { fetchLessons } from '../store/slices/lessonSlice';
import Navbar from '../components/Common/Navbar';

const Dashboard = () => {
  const dispatch = useDispatch();
  const { user } = useSelector(state => state.auth);
  const { lessons, loading } = useSelector(state => state.lesson);
  const [greeting, setGreeting] = useState('');
  const [activeTab, setActiveTab] = useState('all');

  useEffect(() => {
    dispatch(fetchLessons());
    
    const hour = new Date().getHours();
    if (hour < 12) setGreeting('Good Morning');
    else if (hour < 17) setGreeting('Good Afternoon');
    else setGreeting('Good Evening');
  }, [dispatch]);

  const stats = [
    { 
      label: 'Total XP', 
      value: user?.xp_points || 0, 
      icon: '⚡', 
      gradient: 'from-amber-500 to-orange-500',
      change: '+125 today'
    },
    { 
      label: 'Current Level', 
      value: user?.level || 1, 
      icon: '🏆', 
      gradient: 'from-violet-500 to-purple-500',
      change: '75% to next'
    },
    { 
      label: 'Day Streak', 
      value: user?.streak_days || 0, 
      icon: '🔥', 
      gradient: 'from-rose-500 to-red-500',
      change: 'Keep it up!'
    },
    { 
      label: 'Signs Mastered', 
      value: user?.total_signs_learned || 0, 
      icon: '✋', 
      gradient: 'from-emerald-500 to-green-500',
      change: '+8 this week'
    },
  ];

  const lessonTabs = [
    { id: 'all', label: 'All', icon: '📚' },
    { id: 'progress', label: 'In Progress', icon: '⏳' },
    { id: 'completed', label: 'Completed', icon: '✅' },
  ];

  const filteredLessons = lessons.filter(lesson => {
    if (activeTab === 'all') return true;
    if (activeTab === 'progress') return lesson.progress > 0 && lesson.progress < 100;
    if (activeTab === 'completed') return lesson.progress === 100;
    return true;
  });

  // XP Calculations
  const xpForNextLevel = (user?.level || 1) * 1000;
  const currentLevelXP = (user?.xp_points || 0) % 1000;
  const xpProgress = (currentLevelXP / 1000) * 100;

  return (
    <div 
      style={{ 
        minHeight: '100vh', 
        backgroundColor: '#0a0a0f', 
        color: 'white',
        position: 'relative',
        overflow: 'hidden'
      }}
    >
      {/* Background Gradients */}
      <div 
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          pointerEvents: 'none',
          zIndex: 0
        }}
      >
        <div 
          style={{
            position: 'absolute',
            top: '-100px',
            left: '20%',
            width: '400px',
            height: '400px',
            background: 'rgba(139, 92, 246, 0.15)',
            borderRadius: '50%',
            filter: 'blur(100px)'
          }}
        />
        <div 
          style={{
            position: 'absolute',
            bottom: '-100px',
            right: '20%',
            width: '300px',
            height: '300px',
            background: 'rgba(59, 130, 246, 0.15)',
            borderRadius: '50%',
            filter: 'blur(80px)'
          }}
        />
      </div>

      <Navbar />
      
      <div 
        style={{ 
          position: 'relative',
          zIndex: 1,
          maxWidth: '1280px', 
          margin: '0 auto', 
          padding: '32px 16px' 
        }}
      >
        
        {/* Welcome Section */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          style={{ marginBottom: '32px' }}
        >
          <p style={{ color: '#9ca3af', fontSize: '14px', marginBottom: '4px' }}>
            {greeting} 👋
          </p>
          <h1 
            style={{ 
              fontSize: '36px', 
              fontWeight: 'bold',
              background: 'linear-gradient(to right, #ffffff, #a78bfa)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              marginBottom: '12px'
            }}
          >
            Namaste, {user?.full_name?.split(' ')[0] || 'Learner'}!
          </h1>
          
          {/* Badges */}
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '12px' }}>
            {user?.streak_days > 0 && (
              <span 
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '8px',
                  padding: '6px 16px',
                  borderRadius: '9999px',
                  background: 'rgba(249, 115, 22, 0.2)',
                  border: '1px solid rgba(249, 115, 22, 0.3)',
                  color: '#fdba74',
                  fontSize: '14px',
                  fontWeight: '500'
                }}
              >
                🔥 {user.streak_days} Day Streak
              </span>
            )}
            <span 
              style={{
                display: 'inline-flex',
                alignItems: 'center',
                gap: '8px',
                padding: '6px 16px',
                borderRadius: '9999px',
                background: 'rgba(139, 92, 246, 0.2)',
                border: '1px solid rgba(139, 92, 246, 0.3)',
                color: '#c4b5fd',
                fontSize: '14px',
                fontWeight: '500'
              }}
            >
              🎯 Level {user?.level || 1}
            </span>
          </div>
        </motion.div>

        {/* Stats Grid */}
        <div 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
            gap: '16px',
            marginBottom: '40px'
          }}
        >
          {stats.map((stat, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              whileHover={{ scale: 1.02, y: -5 }}
              style={{
                background: 'rgba(255, 255, 255, 0.05)',
                backdropFilter: 'blur(10px)',
                borderRadius: '16px',
                padding: '20px',
                border: '1px solid rgba(255, 255, 255, 0.1)',
                cursor: 'pointer',
                position: 'relative',
                overflow: 'hidden'
              }}
            >
              {/* Top gradient line */}
              <div 
                style={{
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  right: 0,
                  height: '3px',
                  background: `linear-gradient(to right, var(--tw-gradient-stops))`,
                  backgroundImage: stat.gradient.includes('amber') 
                    ? 'linear-gradient(to right, #f59e0b, #f97316)'
                    : stat.gradient.includes('violet')
                    ? 'linear-gradient(to right, #8b5cf6, #a855f7)'
                    : stat.gradient.includes('rose')
                    ? 'linear-gradient(to right, #f43f5e, #ef4444)'
                    : 'linear-gradient(to right, #10b981, #22c55e)'
                }}
              />
              
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px' }}>
                <div 
                  style={{
                    width: '48px',
                    height: '48px',
                    borderRadius: '12px',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: '24px',
                    backgroundImage: stat.gradient.includes('amber') 
                      ? 'linear-gradient(to bottom right, #f59e0b, #f97316)'
                      : stat.gradient.includes('violet')
                      ? 'linear-gradient(to bottom right, #8b5cf6, #a855f7)'
                      : stat.gradient.includes('rose')
                      ? 'linear-gradient(to bottom right, #f43f5e, #ef4444)'
                      : 'linear-gradient(to bottom right, #10b981, #22c55e)'
                  }}
                >
                  {stat.icon}
                </div>
                <span 
                  style={{
                    fontSize: '11px',
                    color: '#34d399',
                    background: 'rgba(52, 211, 153, 0.1)',
                    padding: '4px 8px',
                    borderRadius: '9999px'
                  }}
                >
                  {stat.change}
                </span>
              </div>
              
              <div style={{ fontSize: '28px', fontWeight: 'bold', marginBottom: '4px' }}>
                {stat.value.toLocaleString()}
              </div>
              <div style={{ fontSize: '14px', color: '#9ca3af' }}>
                {stat.label}
              </div>
            </motion.div>
          ))}
        </div>

        {/* Main Content */}
        <div 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: '1fr',
            gap: '32px'
          }}
          className="lg-grid"
        >
          
          {/* Lessons Section */}
          <div>
            {/* Section Header */}
            <div 
              style={{ 
                display: 'flex', 
                flexDirection: 'column',
                gap: '16px',
                marginBottom: '24px'
              }}
            >
              <h2 style={{ fontSize: '24px', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '12px' }}>
                <span 
                  style={{
                    width: '40px',
                    height: '40px',
                    borderRadius: '12px',
                    background: 'linear-gradient(to bottom right, #8b5cf6, #6366f1)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center'
                  }}
                >
                  📚
                </span>
                Continue Learning
              </h2>
              
              {/* Tabs */}
              <div 
                style={{ 
                  display: 'flex', 
                  gap: '8px',
                  padding: '4px',
                  background: 'rgba(255, 255, 255, 0.05)',
                  borderRadius: '12px',
                  width: 'fit-content'
                }}
              >
                {lessonTabs.map((tab) => (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    style={{
                      padding: '8px 16px',
                      borderRadius: '8px',
                      fontSize: '14px',
                      fontWeight: '500',
                      border: 'none',
                      cursor: 'pointer',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '6px',
                      background: activeTab === tab.id 
                        ? 'linear-gradient(to right, #8b5cf6, #6366f1)' 
                        : 'transparent',
                      color: activeTab === tab.id ? 'white' : '#9ca3af',
                      transition: 'all 0.3s ease'
                    }}
                  >
                    <span>{tab.icon}</span>
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Lessons Grid */}
            {loading ? (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {[1, 2, 3].map(i => (
                  <div 
                    key={i}
                    style={{
                      height: '100px',
                      background: 'rgba(255, 255, 255, 0.05)',
                      borderRadius: '16px',
                      animation: 'pulse 2s infinite'
                    }}
                  />
                ))}
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {filteredLessons.length === 0 ? (
                  <div 
                    style={{
                      textAlign: 'center',
                      padding: '48px 24px',
                      background: 'rgba(255, 255, 255, 0.05)',
                      borderRadius: '16px',
                      border: '1px solid rgba(255, 255, 255, 0.1)'
                    }}
                  >
                    <div style={{ fontSize: '48px', marginBottom: '12px' }}>
                      {activeTab === 'completed' ? '🎯' : '📝'}
                    </div>
                    <p style={{ color: '#9ca3af' }}>
                      {activeTab === 'completed' 
                        ? 'No completed lessons yet. Keep learning!' 
                        : 'No lessons in progress.'}
                    </p>
                  </div>
                ) : (
                  filteredLessons.slice(0, 6).map((lesson, index) => (
                    <LessonCard key={lesson.id} lesson={lesson} index={index} />
                  ))
                )}
              </div>
            )}
          </div>

          {/* Sidebar */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            
            {/* XP Progress */}
            <motion.div
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.3 }}
              style={{
                background: 'rgba(255, 255, 255, 0.05)',
                backdropFilter: 'blur(10px)',
                borderRadius: '16px',
                padding: '20px',
                border: '1px solid rgba(255, 255, 255, 0.1)'
              }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                <h3 style={{ fontSize: '18px', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '8px' }}>
                  ⚡ Level Progress
                </h3>
                <span 
                  style={{ 
                    fontSize: '24px', 
                    fontWeight: 'bold',
                    background: 'linear-gradient(to right, #a78bfa, #818cf8)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent'
                  }}
                >
                  Lvl {user?.level || 1}
                </span>
              </div>

              {/* Progress Bar */}
              <div 
                style={{
                  height: '12px',
                  background: 'rgba(255, 255, 255, 0.1)',
                  borderRadius: '9999px',
                  overflow: 'hidden',
                  marginBottom: '12px'
                }}
              >
                <motion.div
                  initial={{ width: 0 }}
                  animate={{ width: `${xpProgress}%` }}
                  transition={{ duration: 1.5, ease: 'easeOut' }}
                  style={{
                    height: '100%',
                    background: 'linear-gradient(to right, #8b5cf6, #6366f1)',
                    borderRadius: '9999px'
                  }}
                />
              </div>

              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '14px' }}>
                <span style={{ color: '#9ca3af' }}>{currentLevelXP} XP</span>
                <span style={{ color: '#a78bfa' }}>1000 XP</span>
              </div>

              <div 
                style={{
                  marginTop: '16px',
                  padding: '12px',
                  background: 'rgba(139, 92, 246, 0.1)',
                  borderRadius: '12px',
                  border: '1px solid rgba(139, 92, 246, 0.2)'
                }}
              >
                <p style={{ fontSize: '14px', color: '#c4b5fd' }}>
                  🎯 {1000 - currentLevelXP} XP to Level {(user?.level || 1) + 1}
                </p>
              </div>
            </motion.div>

            {/* Daily Goals */}
            <motion.div
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.4 }}
              style={{
                background: 'rgba(255, 255, 255, 0.05)',
                backdropFilter: 'blur(10px)',
                borderRadius: '16px',
                padding: '20px',
                border: '1px solid rgba(255, 255, 255, 0.1)'
              }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                <h3 style={{ fontSize: '18px', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '8px' }}>
                  🎯 Daily Goals
                </h3>
                <span 
                  style={{
                    fontSize: '12px',
                    background: 'rgba(52, 211, 153, 0.2)',
                    color: '#34d399',
                    padding: '4px 12px',
                    borderRadius: '9999px'
                  }}
                >
                  2/3 Done
                </span>
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                <GoalItem icon="⏱️" label="Practice Time" current={15} target={30} unit="min" />
                <GoalItem icon="✋" label="Signs Learned" current={8} target={10} />
                <GoalItem icon="📚" label="Lessons Done" current={3} target={3} />
              </div>
            </motion.div>

            {/* Quick Practice Button */}
            <Link to="/practice" style={{ textDecoration: 'none' }}>
              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                style={{
                  width: '100%',
                  padding: '16px 24px',
                  background: 'linear-gradient(to right, #8b5cf6, #6366f1)',
                  border: 'none',
                  borderRadius: '16px',
                  color: 'white',
                  fontSize: '16px',
                  fontWeight: 'bold',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '12px'
                }}
              >
                <span style={{ fontSize: '20px' }}>📷</span>
                Practice with Webcam
              </motion.button>
            </Link>

            {/* Achievements */}
            <motion.div
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.5 }}
              style={{
                background: 'rgba(255, 255, 255, 0.05)',
                backdropFilter: 'blur(10px)',
                borderRadius: '16px',
                padding: '20px',
                border: '1px solid rgba(255, 255, 255, 0.1)'
              }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                <h3 style={{ fontSize: '18px', fontWeight: '600' }}>Recent Achievements</h3>
                <Link to="/achievements" style={{ fontSize: '14px', color: '#a78bfa', textDecoration: 'none' }}>
                  View All
                </Link>
              </div>
              <div style={{ display: 'flex', gap: '12px' }}>
                {['🎯', '🔥', '⭐', '🏆'].map((emoji, i) => (
                  <motion.div
                    key={i}
                    whileHover={{ scale: 1.1 }}
                    style={{
                      width: '48px',
                      height: '48px',
                      borderRadius: '12px',
                      background: 'rgba(255, 255, 255, 0.1)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontSize: '20px',
                      opacity: i > 1 ? 0.3 : 1,
                      filter: i > 1 ? 'grayscale(100%)' : 'none'
                    }}
                  >
                    {emoji}
                  </motion.div>
                ))}
              </div>
            </motion.div>
          </div>
        </div>
      </div>

      {/* CSS for responsive grid */}
      <style>{`
        @media (min-width: 1024px) {
          .lg-grid {
            grid-template-columns: 2fr 1fr !important;
          }
        }
        
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
      `}</style>
    </div>
  );
};

// Lesson Card Component
const LessonCard = ({ lesson, index }) => {
  const progress = lesson.progress || 0;
  
  const getDifficultyColor = (difficulty) => {
    const colors = {
      beginner: '#22c55e',
      intermediate: '#f59e0b',
      advanced: '#ef4444',
    };
    return colors[difficulty] || colors.beginner;
  };

  return (
    <Link to={`/lesson/${lesson.id}`} style={{ textDecoration: 'none', color: 'inherit' }}>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: index * 0.1 }}
        whileHover={{ scale: 1.01, x: 5 }}
        style={{
          background: 'rgba(255, 255, 255, 0.05)',
          backdropFilter: 'blur(10px)',
          borderRadius: '16px',
          padding: '20px',
          border: '1px solid rgba(255, 255, 255, 0.1)',
          cursor: 'pointer',
          position: 'relative',
          overflow: 'hidden'
        }}
      >
        {/* Bottom progress line */}
        <div 
          style={{
            position: 'absolute',
            bottom: 0,
            left: 0,
            right: 0,
            height: '3px',
            background: 'rgba(255, 255, 255, 0.1)'
          }}
        >
          <div 
            style={{
              width: `${progress}%`,
              height: '100%',
              background: progress === 100 
                ? 'linear-gradient(to right, #22c55e, #10b981)'
                : 'linear-gradient(to right, #8b5cf6, #6366f1)',
              transition: 'width 0.5s ease'
            }}
          />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          {/* Icon */}
          <div 
            style={{
              width: '56px',
              height: '56px',
              borderRadius: '12px',
              background: `linear-gradient(to bottom right, ${getDifficultyColor(lesson.difficulty)}, ${getDifficultyColor(lesson.difficulty)}cc)`,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '24px',
              flexShrink: 0
            }}
          >
            {lesson.icon || '📖'}
          </div>

          {/* Info */}
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '4px' }}>
              <h3 style={{ fontSize: '16px', fontWeight: '600', margin: 0 }}>
                {lesson.title}
              </h3>
              {progress === 100 && <span style={{ color: '#22c55e' }}>✓</span>}
            </div>
            <p style={{ fontSize: '14px', color: '#9ca3af', margin: '0 0 8px 0' }}>
              {lesson.description}
            </p>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
              <span style={{ fontSize: '12px', color: '#6b7280', display: 'flex', alignItems: 'center', gap: '4px' }}>
                ⏱️ {lesson.duration || '10 min'}
              </span>
              <span style={{ fontSize: '12px', color: '#6b7280', display: 'flex', alignItems: 'center', gap: '4px' }}>
                ✋ {lesson.signs_count || 10} signs
              </span>
              <span 
                style={{ 
                  fontSize: '11px', 
                  padding: '2px 8px', 
                  borderRadius: '9999px',
                  background: `${getDifficultyColor(lesson.difficulty)}20`,
                  color: getDifficultyColor(lesson.difficulty),
                  textTransform: 'capitalize'
                }}
              >
                {lesson.difficulty || 'Beginner'}
              </span>
            </div>
          </div>

          {/* Progress Circle */}
          <div style={{ flexShrink: 0, position: 'relative', width: '56px', height: '56px' }}>
            <svg width="56" height="56" style={{ transform: 'rotate(-90deg)' }}>
              <circle
                cx="28"
                cy="28"
                r="24"
                fill="none"
                stroke="rgba(255,255,255,0.1)"
                strokeWidth="4"
              />
              <circle
                cx="28"
                cy="28"
                r="24"
                fill="none"
                stroke="url(#gradient)"
                strokeWidth="4"
                strokeLinecap="round"
                strokeDasharray={`${progress * 1.51} 151`}
              />
              <defs>
                <linearGradient id="gradient">
                  <stop offset="0%" stopColor="#8b5cf6" />
                  <stop offset="100%" stopColor="#6366f1" />
                </linearGradient>
              </defs>
            </svg>
            <span 
              style={{ 
                position: 'absolute', 
                inset: 0, 
                display: 'flex', 
                alignItems: 'center', 
                justifyContent: 'center',
                fontSize: '12px',
                fontWeight: '600'
              }}
            >
              {progress}%
            </span>
          </div>
        </div>
      </motion.div>
    </Link>
  );
};

// Goal Item Component
const GoalItem = ({ icon, label, current, target, unit = '' }) => {
  const progress = Math.min((current / target) * 100, 100);
  const isComplete = current >= target;

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
        <span style={{ fontSize: '14px', color: '#d1d5db', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <span>{icon}</span>
          {label}
        </span>
        <span style={{ fontSize: '14px', fontWeight: '500', color: isComplete ? '#34d399' : '#9ca3af' }}>
          {current}/{target}{unit && ` ${unit}`}
          {isComplete && ' ✓'}
        </span>
      </div>
      <div 
        style={{
          height: '8px',
          background: 'rgba(255, 255, 255, 0.1)',
          borderRadius: '9999px',
          overflow: 'hidden'
        }}
      >
        <motion.div
          initial={{ width: 0 }}
          animate={{ width: `${progress}%` }}
          transition={{ duration: 1, ease: 'easeOut' }}
          style={{
            height: '100%',
            background: isComplete 
              ? 'linear-gradient(to right, #22c55e, #10b981)'
              : 'linear-gradient(to right, #8b5cf6, #6366f1)',
            borderRadius: '9999px'
          }}
        />
      </div>
    </div>
  );
};

export default Dashboard;
